// Extract unique parameters for Monthly Report formula indexing
export const uniqueParams = [];
REPORTS_CONFIG.forEach(report => {
  report.params.forEach(p => {
    if (!uniqueParams.includes(p)) {
      uniqueParams.push(p);
    }
  });
});
